12	export type Scenario = {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	};
16	
17	export type QuoteResult = { premium: number };
18	export type StepResult = QuoteResult;
19	export type ScenarioResult = { results: StepResult[] };
