21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
32	
33	const sumItemBasePremiums = (items: Item[]): number =>
34	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
35	
36	const quoteStep = (step: QuoteStep): QuoteResult => {
37	  const itemsBase = sumItemBasePremiums(step.items);
38	  const firstInsuranceSurcharge = itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
39	  const premium = Math.ceil(itemsBase + firstInsuranceSurcharge + PROCESSING_FEE);
40	  return { premium };
41	};
42	
43	export const runScenario = (scenario: Scenario): ScenarioResult => ({
44	  results: scenario.steps.map(quoteStep),
45	});
